/**
 * Regression test for non-legacy mail content decryption failure
 *
 * This test demonstrates the bug where loading mail details (MailDetailsBlob or MailDetailsDraft)
 * with an owner-encrypted session key fails when the MailDetailsBlob/Draft has a different
 * _ownerGroup than the parent Mail object.
 *
 * The issue is that the session key is encrypted with the parent Mail's _ownerGroup,
 * but when it's set on the MailDetailsBlob and resolveSessionKey tries to decrypt it,
 * it uses the MailDetailsBlob's _ownerGroup, which causes decryption to fail with
 * "Missing decryption key" error.
 */

import o from "@tutao/otest"
import {
	aes128RandomKey,
	bitArrayToUint8Array,
	decryptKey,
	encryptKey,
	ENABLE_MAC,
	hexToPrivateKey,
	hexToPublicKey,
	IV_BYTE_LENGTH,
	random,
	aes128Encrypt,
} from "@tutao/tutanota-crypto"
import {
	base64ToUint8Array,
	downcast,
	uint8ArrayToBase64,
	neverNull,
	stringToUtf8Uint8Array,
} from "@tutao/tutanota-utils"
import { CryptoFacade } from "../src/api/worker/crypto/CryptoFacade.js"
import { RestClient } from "../src/api/worker/rest/RestClient.js"
import { EntityClient } from "../src/api/common/EntityClient.js"
import { RsaWeb } from "../src/api/worker/crypto/RsaImplementation.js"
import { InstanceMapper } from "../src/api/worker/crypto/InstanceMapper.js"
import { UserFacade } from "../src/api/worker/facades/UserFacade.js"
import { OwnerEncSessionKeysUpdateQueue } from "../src/api/worker/crypto/OwnerEncSessionKeysUpdateQueue.js"
import {
	createMail,
	createMailDetailsBlob,
	createMailAddress,
	createMailDetails,
	createBody,
	createHeader,
	createRecipients,
	createEncryptedMailAddress,
	MailDetailsBlobTypeRef,
	MailTypeRef,
} from "../src/api/entities/tutanota/TypeRefs.js"
import {
	createGroup,
	createGroupMembership,
	createKeyPair,
	createUser,
	GroupTypeRef,
	PermissionTypeRef,
	BucketKeyTypeRef,
	createBucketKey,
	createBucketPermission,
	createPermission,
	createInstanceSessionKey,
} from "../src/api/entities/sys/TypeRefs.js"
import { IServiceExecutor } from "../src/api/common/ServiceRequest.js"
import { matchers, object, when } from "testdouble"
import { resolveTypeReference } from "../src/api/common/EntityFunctions.js"
import { SessionKeyNotFoundError } from "../src/api/common/error/SessionKeyNotFoundError.js"
import { BucketPermissionType, PermissionType } from "../src/api/common/TutanotaConstants.js"
import { elementIdPart, listIdPart } from "../src/api/common/utils/EntityUtils.js"

const { anything } = matchers

o.spec("Non-legacy mail decryption regression test", function () {
	let crypto: CryptoFacade
	let userFacade: UserFacade
	let entityClient: EntityClient
	let instanceMapper: InstanceMapper
	let restClient: RestClient
	let serviceExecutor: IServiceExecutor
	let ownerEncSessionKeysUpdateQueue: OwnerEncSessionKeysUpdateQueue

	// RSA key pair for testing
	const rsaPrivateHexKey =
		""
	const rsaPublicHexKey =
		""

	o.before(async function () {
		const suspensionHandler = downcast({})
		restClient = new RestClient(suspensionHandler)
		instanceMapper = new InstanceMapper()
		ownerEncSessionKeysUpdateQueue = new OwnerEncSessionKeysUpdateQueue()
		serviceExecutor = object<IServiceExecutor>()

		// Mock entity client
		entityClient = object<EntityClient>()

		// Setup user facade with mocked groups
		userFacade = object<UserFacade>()

		// Create RSA instance for crypto operations
		const rsa = new RsaWeb()

		// Initialize crypto facade
		crypto = new CryptoFacade(
			userFacade,
			entityClient,
			restClient,
			rsa,
			serviceExecutor,
			instanceMapper,
			ownerEncSessionKeysUpdateQueue,
		)
	})

	o(
		"Should fail to decrypt MailDetailsBlob when _ownerEncSessionKey is encrypted with different group key",
		async function () {
			// This test demonstrates the regression where session key propagation fails
			// when the parent Mail and child MailDetailsBlob have different _ownerGroups

			// Setup: Create two different group keys (simulating different owner groups)
			const mailGroupKey = aes128RandomKey() // Group A key
			const detailsGroupKey = aes128RandomKey() // Group B key (different from mail's group)

			const mailGroupId = "mailGroupId123"
			const detailsGroupId = "detailsGroupId456" // Different from mailGroupId

			// Create a session key for the mail content
			const mailSessionKey = aes128RandomKey()

			// Encrypt the session key with mailGroupKey (this is what the server stores)
			const mailOwnerEncSessionKey = encryptKey(mailGroupKey, mailSessionKey)

			// Setup: Mock userFacade to return different group keys
			when(userFacade.isFullyLoggedIn()).thenReturn(true)
			when(userFacade.hasGroup(mailGroupId)).thenReturn(true)
			when(userFacade.hasGroup(detailsGroupId)).thenReturn(true)
			when(userFacade.getGroupKey(mailGroupId)).thenReturn(mailGroupKey)
			when(userFacade.getGroupKey(detailsGroupId)).thenReturn(detailsGroupKey) // Returns DIFFERENT key!

			// Create a Mail with the session key encrypted under mailGroupId
			const mail = createMail({
				_ownerGroup: mailGroupId,
				_ownerEncSessionKey: mailOwnerEncSessionKey,
				_id: ["mailListId", "mailElementId"],
				subject: "Test Mail",
				sender: createMailAddress(),
			})

			// Create a MailDetailsBlob with a DIFFERENT _ownerGroup
			// In the real bug, this represents a MailDetailsBlob that belongs to a different group
			const mailDetailsBlob = {
				_type: MailDetailsBlobTypeRef,
				_format: "0",
				_id: ["detailsListId", "detailsElementId"],
				_ownerGroup: detailsGroupId, // Different from mail's ownerGroup!
				_ownerEncSessionKey: null, // This will be set from the mail's key
				_permissions: "permId",
				_errors: {},
				details: {
					_id: "detailId",
					authStatus: "0",
					sentDate: new Date(),
					body: { text: "encrypted content" },
					headers: null,
					recipients: createRecipients(),
					replyTos: [],
				},
			}

			// Simulate what happens in loadMultiple with providedOwnerEncSessionKeys
			const providedOwnerEncSessionKeys = new Map<string, Uint8Array>()
			providedOwnerEncSessionKeys.set(
				elementIdPart(mailDetailsBlob._id),
				mailOwnerEncSessionKey, // Using the mail's encrypted key
			)

			// This simulates the code in _handleLoadMultipleResult (EntityRestClient.ts line 276)
			mailDetailsBlob._ownerEncSessionKey = providedOwnerEncSessionKeys.get(elementIdPart(mailDetailsBlob._id))!

			// Now try to resolve the session key for the MailDetailsBlob
			// This is where the bug manifests: resolveSessionKey will try to decrypt
			// mailOwnerEncSessionKey (encrypted with mailGroupKey) using detailsGroupKey
			const typeModel = await resolveTypeReference(MailDetailsBlobTypeRef)

			try {
				const resolvedKey = await crypto.resolveSessionKey(typeModel, mailDetailsBlob)
				// If we get here without error, the bug is fixed
				// The test should NOT reach this point in the current (buggy) code
				o(resolvedKey).notEquals(null)("Session key should be resolved")
			} catch (e: any) {
				// The current (buggy) code will throw an error here
				// because it tries to decrypt mailOwnerEncSessionKey with the wrong group key (detailsGroupKey)
				if (e instanceof SessionKeyNotFoundError) {
